async () => {
  const res = await cloudflare.request({
    method: "GET",
    path: `/accounts/${accountId}/pages/projects/begbie-hugo/deployments`,
    query: { per_page: 5 }
  });
  return res.result?.map(d => ({
    id: d.id,
    created_on: d.created_on,
    latest_stage: d.latest_stage,
    environment: d.environment,
    url: d.url,
    deployment_trigger: d.deployment_trigger
  }));
}

